test_cases.assertion_pseudocode:
// Static analysis / compilation check
// Attempt to reference apikit.ErrKeyRevoked, apikit.ErrKeyExpired, etc.
// Each must produce a compile error: 'undefined: apikit.ErrKeyRevoked'
exportedSymbols = getExportedSymbols('apikit')
assert 'APIKeyResult' in exportedSymbols
assert 'GenerateAPIKey' in exportedSymbols
assert 'ErrKeyRevoked' not in exportedSymbols
assert 'ErrKeyExpired' not in exportedSymbols

for path, method in [('/api/v1/user/keys','GET'), ('/api/v1/user/keys/testkey/refresh','POST'), ('/api/v1/user/keys/testkey','DELETE')]:
    resp = makeRequest(method, path, headers={'Authorization': 'Bearer ak_testkey_testsecret'})
    assert resp.headers['Cache-Control'] == 'no-store'

// API key auth
resp1 = GET('/api/v1/user/keys', auth=user017APIKey)
assert resp1.status == 200

// PAT with keys:read
resp2 = GET('/api/v1/user/keys', auth=user017PATWithKeysRead)
assert resp2.status == 200

// Static check: no package-level logger variable
sourceFiles = readDir('internal/keys/')
for file in sourceFiles:
    assert not containsPattern(file, 'var\s+\w*[Ll]og\w*\s+echo\.Logger')
    assert not containsPattern(file, 'var\s+\w*[Ll]og\w*\s+=\s+log\.New')
// Signature check
assert functionSignatureContains('GenerateAPIKey', 'logger echo.Logger')

edge_case_tests.assertion_pseudocode:
// Pre-insert rows for all 3 expected key_ids to force collision
for keyID in getFirst3GeneratedKeyIDs():
    db.exec('INSERT INTO api_keys (key_id, user_id, secret_hash, expires_days, created_at) VALUES (?, ?, ?, ?, ?)', keyID, 'other', 'hash', 0, now())
result, err = GenerateAPIKey(db, 'user-E6', 90, logger)
assert err != nil
assert result == nil
// Simulate HTTP layer:
resp = callViaHandler(GenerateAPIKey, db, 'user-E6', 90)
assert resp.status == 500
assert parseJSON(resp.body).error == 'internal server error'
